template<typename T>
class MyAlloc {
public:
    using value_type = T;
    T* allocate(std::size_t n) { return new T[n]; }
    void deallocate(T* p, std::size_t) { delete[] p; }
};

std::list<int, MyAlloc<int>> lst;
lst.push_back(42);

